const leads = $input.first().json.data || [];
const ready = leads.filter(l => l.email && l.emailValid === 'valid' && l.status === 'new').slice(0, 3).map(l => ({leadId: l.id, businessName: l.businessName, website: l.website, email: l.email, city: l.city, state: l.state, websiteScore: l.websiteScore || '50'}));
return {leads: ready, count: ready.length};

const lead = $input.first().json;
const score = parseInt(lead.websiteScore) || 50;
let tone = 'professional';
let category = 'optimization';
if (score < 30) { tone = 'urgent'; category = 'redesign'; }
else if (score < 50) { tone = 'concerned'; category = 'improvement'; }
else if (score < 70) { tone = 'helpful'; category = 'optimization'; }
else { tone = 'complimentary'; category = 'minor'; }

const prompt = `Write a cold outreach email for an architecture firm with these details:
Business: ${lead.businessName}
Website: ${lead.website}
Location: ${lead.city}, ${lead.state}
Website Score: ${score}/100
Category: ${category}
Tone: ${tone}

Include:
1. Personal mention of their firm
2. Specific observation about their website
3. Value proposition for landing page design
4. Soft CTA for a call

Return JSON: {"subject": "...", "body": "..."}`;

return {lead, prompt, tone, category, score};

const aiResp = $input.first().json;
const promptData = $('Build AI Prompt').first().json;

let emailContent = {subject: 'Improving ' + promptData.lead.businessName, body: 'Hi,\n\nI noticed your website and wanted to share how we help architecture firms get more clients with modern landing pages.\n\nWould you be open to a quick call?\n\nBest regards'};

try {
  const content = aiResp.choices?.[0]?.message?.content;
  if (content) {
    const parsed = JSON.parse(content);
    if (parsed.subject && parsed.body) emailContent = parsed;
  }
} catch(e) {}

return {leadId: promptData.lead.leadId, businessName: promptData.lead.businessName, email: promptData.lead.email, subject: emailContent.subject, body: emailContent.body, tone: promptData.tone, category: promptData.category, generatedAt: new Date().toISOString()};
